package algorithm;

import java.util.Scanner;

public class P_10869 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		Scanner s = new Scanner(System.in);
		
		int a = s.nextInt();
		int b = s.nextInt();
		
		System.out.println((a + b) +"\n"+ (a - b) + "\n" + (a * b) + "\n" + (a / b) + "\n" + (a % b));
		
	}

}
/*
 * + : 더히기
 * - : 빼기
 * * : 곱하기
 * / : 몫
 * % : 나머지
 * */
 